    """
    Find the valid alpha/beta packet with the highest token-sum score.

    Args:
        packets: A list of Fluxon packets.

    Returns:
        The valid alpha/beta packet with the highest token-sum score, or None if no valid packet is found.
    """
    valid_packets = []
    for packet in packets:
        try:
            record = parse_fluxon_packet(packet)
            if record["channel"] in ("alpha", "beta"):
