    if not valid_packets:
        return None

    highest_score = 0
    winning_packet = None
    for packet in valid_packets:
        token_sum = sum(token_value(token) for token in packet["tokens"])
        if token_sum > highest_score:
            highest_score = token_sum
            winning_packet = packet

    return winning_packet["payload"]

