    packets = []
    for frame in frames:
        try:
            packet = decode_fluxon_frame(frame)
            if validate_fluxon_packet(packet):
                packets.append(packet)
        except ValueError:
            pass

    # Average normalized token sums by channel
    results = {}
    for packet in packets:
        channel = packet["channel"]
        tokens = packet["tokens"]
        values = [token_value(token) for token in tokens]
        normalized = [normalize_channel_value(value, channel) for value in values]
        sum = sum(normalized)
        count = len(normalized)
        if channel not in results:
